1	//! Graph GENERATION (BEHAVIOR.md §6): mapping a proof-state / constraint-system
2	//! description onto the DOT [`Graph`] model, over an independent input model
3	//! designed from observed paired `main/proof` sequents and `interactive-graph-def`
4	//! graphs.
5	//!
6	//! What the observed system→graph mapping does, structurally (each point traces to
7	//! corpus/live observation — see BEHAVIOR.md §6):
8	//!   * a **rule instance** `#t : Rule[actions]` becomes a `record` node with up to
9	//!     three groups `{premises}|{info}|{conclusions}`; the **info** group (the
10	//!     `#t : Rule[…]` cell) is always present (100 % of 160 409 corpus records),
11	//!     and an **empty** premise or conclusion group is dropped (so a source rule
12	//!     with no premises renders `{info}|{concl}`);
13	//!   * an intruder-knowledge fact renders as a gray `!KU( m ) @ #t` **ellipse**;
14	//!     a protocol action/event as a darkblue `Fact @ #t` ellipse; a compressed
15	//!     intruder rule as an uncolored `#t : rule` ellipse;
16	//!   * an unresolved node referenced by an open premise renders as an
17	//!     **invtrapezium** `(#var, idx)` (BEHAVIOR.md §3d);
18	//!   * **edges** connect a conclusion port to a premise port (structural), or an
19	//!     intruder deduction (red dashed), message (gray30), temporal order (blue3 /
20	//!     black dashed), etc. — the finite observed style vocabulary (§3c);
21	//!   * `n<K>` ids come from [`crate::alloc`]; the header is inferred by role (§4).
22	//!
23	//! GAPS (need the GPL solver; not derivable from output): *which* nodes/edges a
24	//! raw constraint system yields (the compression content), the per-rule color
25	//! hash, and record-cell line wrapping. This layer takes node/edge lists, colors,
26	//! and pre-rendered cell text as INPUTS and assembles the exact DOT structure.
27	
28	use crate::alloc::NodeIdAllocator;
29	use crate::model::*;
30	use crate::render::{escape_record, Fact};
31	
32	/// A rule instance: one record node with premise / info / conclusion cells.
33	#[derive(Clone, Debug)]
34	pub struct RuleInstance {
35	    pub temporal: String,
36	    pub rule: String,
37	    pub role: String,
38	    pub premises: Vec<Fact>,
39	    pub actions: Vec<Fact>,
40	    pub conclusions: Vec<Fact>,
41	    /// Per-rule fill color (a solver-side hash — a GAP; supplied by the caller).
42	    pub fillcolor: String,
43	    /// `black` on the light MSR palette, `white` on the saturated role palette.
44	    pub fontcolor: String,
45	}
46	
47	impl RuleInstance {
48	    pub fn new(temporal: &str, rule: &str, fillcolor: &str) -> Self {
49	        RuleInstance {
50	            temporal: temporal.into(),
51	            rule: rule.into(),
52	            role: Role::UNDEFINED.into(),
53	            premises: Vec::new(),
54	            actions: Vec::new(),
55	            conclusions: Vec::new(),
56	            fillcolor: fillcolor.into(),
57	            fontcolor: "black".into(),
58	        }
59	    }
60	    pub fn premises(mut self, f: Vec<Fact>) -> Self {
61	        self.premises = f;
62	        self
63	    }
64	    pub fn actions(mut self, f: Vec<Fact>) -> Self {
65	        self.actions = f;
66	        self
67	    }
68	    pub fn conclusions(mut self, f: Vec<Fact>) -> Self {
69	        self.conclusions = f;
70	        self
71	    }
72	    pub fn role(mut self, r: &str, fontcolor: &str) -> Self {
73	        self.role = r.into();
74	        self.fontcolor = fontcolor.into();
75	        self
76	    }
77	    fn cell_count(&self) -> usize {
78	        let p = self.premises.len();
79	        let c = self.conclusions.len();
80	        p + 1 /* info */ + c
81	    }
82	}
83	
84	/// One node of the input system, in emission order.
85	#[derive(Clone, Debug)]
86	pub enum GraphNode {
87	    Rule(RuleInstance),
88	    /// `!KU( term ) @ #t` — intruder knowledge (drawn as a gray ellipse). `term`
89	    /// is the pre-rendered message text.
90	    Knowledge { term: String, temporal: String },
91	    /// `Fact @ #t` — a protocol action/event (darkblue ellipse). `fact` is
92	    /// pre-rendered.
93	    Action { fact: String, temporal: String },
94	    /// `#t : rule` — a compressed rule shown as a single uncolored ellipse.
95	    Compressed { temporal: String, rule: String },
96	    /// `(#var, idx)` — an unresolved node referenced by an open premise
97	    /// (invtrapezium).
98	    OpenTarget { node_var: String, premise_index: usize },
99	}
100	
101	/// An endpoint reference into the input system (resolved to `n<K>[:n<port>]`).
102	#[derive(Clone, Copy, Debug)]
103	pub enum EndRef {
104	    /// The whole node (no port) — ellipses, invtrapezium, legend.
105	    Whole(usize),
106	    /// Conclusion `c` of rule node `n` (→ its conclusion port).
107	    Conclusion(usize, usize),
108	    /// Premise `p` of rule node `n` (→ its premise port).
109	    Premise(usize, usize),
110	}
111	
112	/// The finite observed edge-style vocabulary (BEHAVIOR.md §3c). Each maps to a
113	/// fixed attribute list emitted verbatim.
114	#[derive(Clone, Copy, Debug)]
115	pub enum EdgeStyle {
116	    /// `style="bold",weight="10.0",color="gray50"` — structural, into a target.
117	    StructuralGray,
118	    /// `style="bold",weight="10.0"` — structural (uncolored).
119	    Structural,
120	    /// `color="gray30"` — message / standard edge.
121	    Message,
122	    /// `color="red",style="dashed"` — intruder `!KU` deduction.
123	    KnowledgeDeduction,
124	    /// `color="orangered2"` — deduction variant.
125	    Deduction,
126	    /// `color="blue3",style="dashed"` — temporal-order edge.
127	    TemporalBlue,
128	    /// `color="black",style="dashed"` — before / less-than temporal edge.
129	    TemporalBlack,
130	    /// `style="invis"` — ranking edge to the legend.
131	    Invis,
132	}
133	
134	impl EdgeStyle {
135	    /// The exact attribute pairs, in observed key order.
136	    pub fn attrs(self) -> Vec<(String, String)> {
137	        let raw: &[(&str, &str)] = match self {
138	            EdgeStyle::StructuralGray => {
139	                &[("style", "bold"), ("weight", "10.0"), ("color", "gray50")]
140	            }
141	            EdgeStyle::Structural => &[("style", "bold"), ("weight", "10.0")],
142	            EdgeStyle::Message => &[("color", "gray30")],
143	            EdgeStyle::KnowledgeDeduction => &[("color", "red"), ("style", "dashed")],
144	            EdgeStyle::Deduction => &[("color", "orangered2")],
145	            EdgeStyle::TemporalBlue => &[("color", "blue3"), ("style", "dashed")],
146	            EdgeStyle::TemporalBlack => &[("color", "black"), ("style", "dashed")],
147	            EdgeStyle::Invis => &[("style", "invis")],
148	        };
149	        raw.iter().map(|(k, v)| (k.to_string(), v.to_string())).collect()
150	    }
151	}
152	
153	/// An edge in the input system.
154	#[derive(Clone, Debug)]
155	pub struct SysEdge {
156	    pub src: EndRef,
157	    pub dst: EndRef,
158	    pub style: EdgeStyle,
159	}
160	
161	impl SysEdge {
162	    pub fn new(src: EndRef, dst: EndRef, style: EdgeStyle) -> Self {
163	        SysEdge { src, dst, style }
164	    }
165	}
166	
167	/// A proof-state graph description: nodes in emission order, edges, and an
168	/// optional pre-rendered legend (inner HTML of the `plain` node) plus the invis
169	/// edges wiring it in.
170	#[derive(Clone, Debug, Default)]
171	pub struct System {
172	    pub nodes: Vec<GraphNode>,
173	    pub edges: Vec<SysEdge>,
174	    /// Legend inner HTML (from [`crate::abbrev::Abbreviator::legend_html`]); if
175	    /// non-empty a `{ rank="sink"; … }` block is appended.
176	    pub legend_html: Option<String>,
177	    /// Invis edges to the legend node (emitted after the sink block).
178	    pub legend_edges: Vec<(EndRef, ())>,
179	}
180	
181	/// Resolved ids for one system node.
182	enum Resolved {
183	    // The info port is never an edge endpoint, so it is not retained here.
184	    Record { ports_prem: Vec<String>, ports_concl: Vec<String>, node: String },
185	    Node(String),
186	}
187	
188	impl Resolved {
189	    fn node_id(&self) -> &str {
190	        match self {
191	            Resolved::Record { node, .. } => node,
192	            Resolved::Node(id) => id,
193	        }
194	    }
195	}
196	
197	/// Build the DOT [`Graph`] for a [`System`]: allocate ids, emit nodes in order,
198	/// then edges, then the legend sink-block + its invis edges. Header is inferred
199	/// from roles.
200	pub fn generate(sys: &System) -> Graph {
201	    let mut alloc = NodeIdAllocator::new();
202	    let mut resolved: Vec<Resolved> = Vec::with_capacity(sys.nodes.len());
203	    let mut g = Graph::new(Header::Simple);
204	
205	    // Pass 1: allocate ids and emit node statements in emission order.
206	    for node in &sys.nodes {
207	        match node {
208	            GraphNode::Rule(r) => {
209	                let ids = alloc.record(r.cell_count());
210	                let mut it = ids.ports.into_iter();
211	                let ports_prem: Vec<String> = (0..r.premises.len()).map(|_| it.next().unwrap()).collect();
212	                let port_info = it.next().unwrap();
213	                let ports_concl: Vec<String> = (0..r.conclusions.len()).map(|_| it.next().unwrap()).collect();
214	                let rec = build_record(r, &ports_prem, &port_info, &ports_concl);
215	                g.push(Stmt::Node(Node::record(ids.node.clone(), rec)));
216	                resolved.push(Resolved::Record { ports_prem, ports_concl, node: ids.node });
217	            }
218	            GraphNode::Knowledge { term, temporal } => {
219	                let id = alloc.node();
220	                let label = format!("!KU( {} ) @ #{}", term, temporal);
221	                g.push(Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "gray"))));
222	                resolved.push(Resolved::Node(id));
223	            }
224	            GraphNode::Action { fact, temporal } => {
225	                let id = alloc.node();
226	                let label = format!("{} @ #{}", fact, temporal);
227	                g.push(Stmt::Node(Node::ellipse(id.clone(), Ellipse::colored(label, "darkblue"))));
228	                resolved.push(Resolved::Node(id));
229	            }
230	            GraphNode::Compressed { temporal, rule } => {
231	                let id = alloc.node();
232	                let label = format!("#{} : {}", temporal, rule);
233	                g.push(Stmt::Node(Node::ellipse(id.clone(), Ellipse::new(label))));
234	                resolved.push(Resolved::Node(id));
235	            }
236	            GraphNode::OpenTarget { node_var, premise_index } => {
237	                let id = alloc.node();
238	                g.push(Stmt::Node(Node::shaped(
239	                    id.clone(),
240	                    Shaped::invtrapezium(node_var, *premise_index),
241	                )));
242	                resolved.push(Resolved::Node(id));
243	            }
244	        }
245	    }
246	
247	    // Pass 2: edges.
248	    for e in &sys.edges {
249	        let src = endpoint(&resolved, e.src);
250	        let dst = endpoint(&resolved, e.dst);
251	        g.push(Stmt::Edge(Edge { src, dst, attrs: e.style.attrs() }));
252	    }
253	
254	    // Pass 3: legend sink-block, then its invis edges (observed order).
255	    if let Some(html) = &sys.legend_html {
256	        if !html.is_empty() {
257	            let legend_id = alloc.node();
258	            let block = RankBlock {
259	                rank: "sink".into(),
260	                body: vec![Stmt::Node(Node::plain(legend_id.clone(), html.clone()))],
261	            };
262	            g.push(Stmt::RankBlock(block));
263	            for (from, ()) in &sys.legend_edges {
264	                let src = endpoint(&resolved, *from);
265	                g.push(Stmt::Edge(Edge {
266	                    src,
267	                    dst: EndPoint::node(legend_id.clone()),
268	                    attrs: EdgeStyle::Invis.attrs(),
269	                }));
270	            }
271	        }
272	    }
273	
274	    g.set_inferred_header();
275	    g
276	}
277	
278	/// Assemble a record node's model from a rule instance and its allocated ports.
279	/// Empty premise / conclusion groups are dropped; the info group is always kept
280	/// (matches the observed group structure).
281	fn build_record(r: &RuleInstance, ports_prem: &[String], port_info: &str, ports_concl: &[String]) -> Record {
282	    let mut columns: Vec<Vec<Cell>> = Vec::new();
283	    if !r.premises.is_empty() {
284	        columns.push(cells(&r.premises, ports_prem));
285	    }
286	    let info_text = crate::render::render_info(&r.temporal, &r.rule, &r.actions);
287	    columns.push(vec![Cell::new(port_info, escape_record(&info_text))]);
288	    if !r.conclusions.is_empty() {
289	        columns.push(cells(&r.conclusions, ports_concl));
290	    }
291	    Record {
292	        columns,
293	        fillcolor: r.fillcolor.clone(),
294	        fontcolor: r.fontcolor.clone(),
295	        role: Role(r.role.clone()),
296	    }
297	}
298	
299	fn cells(facts: &[Fact], ports: &[String]) -> Vec<Cell> {
300	    facts
301	        .iter()
302	        .zip(ports)
303	        .map(|(f, p)| Cell::new(p.clone(), escape_record(&f.render_flat())))
304	        .collect()
305	}
306	
307	/// Resolve an [`EndRef`] to a serializer [`EndPoint`] using the id/port map.
308	fn endpoint(resolved: &[Resolved], r: EndRef) -> EndPoint {
309	    match r {
310	        EndRef::Whole(n) => EndPoint::node(resolved[n].node_id().to_string()),
311	        EndRef::Conclusion(n, c) => {
312	            if let Resolved::Record { node, ports_concl, .. } = &resolved[n] {
313	                EndPoint::port(node.clone(), ports_concl[c].clone())
314	            } else {
315	                EndPoint::node(resolved[n].node_id().to_string())
316	            }
317	        }
318	        EndRef::Premise(n, p) => {
319	            if let Resolved::Record { node, ports_prem, .. } = &resolved[n] {
320	                EndPoint::port(node.clone(), ports_prem[p].clone())
321	            } else {
322	                EndPoint::node(resolved[n].node_id().to_string())
323	            }
324	        }
325	    }
326	}
