1	//! Record-cell rendering (BEHAVIOR.md §3a, §3f): turning facts / rule instances
2	//! into the exact text that goes inside a record cell, including the observed
3	//! escaping, the fact-vs-function spacing, and the `\l`/`&nbsp;` line-wrapping
4	//! FORMAT.
5	//!
6	//! What is byte-exact here (verified against the corpus):
7	//!   * **Escaping** of record-label metacharacters `< > { } |`.
8	//!   * **Fact spacing** `Name( a, b )` (a space after `(` and before `)`) versus
9	//!     **function spacing** `f(a, b)` (no inner spaces) — mined over the corpus;
10	//!     a fact / relation symbol pads, an ordinary function application does not.
11	//!   * **Info-cell** shape `#<temporal> : <RuleName>` optionally followed by
12	//!     `[<action>, …]`.
13	//!   * The **wrap alignment**: a broken group's continuation lines are indented
14	//!     with `&nbsp;` runs to the column of the group's first element — i.e. just
15	//!     after `( ` for a fact, after `<` for a tuple, after `[` for an action list
16	//!     (verified across 188 192 wrapped cells: the indent always equals that
17	//!     first-element column). Physical segments are separated by `\l`.
18	//!
19	//! The wrap DECISION (BEHAVIOR.md §3f) — previously a documented GAP — is now
20	//! pinned by controlled probing: a fact is pretty-printed **from column 0 with an
21	//! absolute line width of [`FILL_WIDTH`] = 87 columns**, using a greedy paragraph
22	//! ("fill") layout. This was established by driving crafted single-node theories
23	//! through the live server and sweeping term width one column at a time: across
24	//! functor names of length 2, 3, 6 and 10 the single-line→wrap boundary always
25	//! fell at total width 87 (fits) / 88 (breaks), i.e. the width is measured from
26	//! the functor's own column, independent of its length. [`fits_one_line`] is that
27	//! decision; [`paragraph_fill`] packs elements greedily to the same width.
28	//!
29	//! Residual (characterised, not byte-implemented): the exact `fsep`-style
30	//! one-element lookahead makes a *continuation* line pack one more element than
31	//! the first line at the same start column, and closing delimiters (`>`, `)`) peel
32	//! onto their own aligned lines in overflow; unbreakable atoms wider than 87
33	//! overflow verbatim. See BEHAVIOR.md §3f.
34	
35	use crate::term::Term;
36	
37	/// Absolute per-fact line width of the record-cell pretty-printer, in columns,
38	/// measured from the functor at column 0. A fact whose flat rendering is `≤ 87`
39	/// columns is emitted on a single line; a wider one is broken (BEHAVIOR.md §3f).
40	/// Pinned by a live one-column width sweep that was invariant across functor
41	/// lengths (the boundary was always flat-width 87 fits / 88 breaks).
42	pub const FILL_WIDTH: usize = 87;
43	
44	/// The wrap DECISION at the top level: a fact stays on a single record-cell line
45	/// iff its flat (un-wrapped) rendering is at most [`FILL_WIDTH`] columns wide.
46	/// `flat` is the fact's flat rendering (e.g. from [`Fact::render_flat`]); width is
47	/// counted in Unicode scalars, matching the observed column count. Verified
48	/// byte-exact at the boundary: an 87-column fact is single-line, an 88-column one
49	/// wraps (live probe, functor-length-invariant).
50	pub fn fits_one_line(flat: &str) -> bool {
51	    flat.chars().count() <= FILL_WIDTH
52	}
53	
54	/// Escape the metacharacters that are special inside a graphviz record label:
55	/// `< > { } |` each get a leading backslash. Everything else (including single
56	/// quotes, `~ $ ^ * ⊕`, spaces) is literal. Observed in every record cell.
57	pub fn escape_record(s: &str) -> String {
58	    let mut out = String::with_capacity(s.len());
59	    for c in s.chars() {
60	        match c {
61	            '<' | '>' | '{' | '}' | '|' => {
62	                out.push('\\');
63	                out.push(c);
64	            }
65	            _ => out.push(c),
66	        }
67	    }
68	    out
69	}
70	
71	/// A fact / relation atom occupying one premise or conclusion cell, e.g.
72	/// `!SessionKey( <…>, $A, H1 )`. `name` is the fact symbol (may start with `!`
73	/// for a persistent fact); `args` are its term arguments.
74	#[derive(Clone, Debug)]
75	pub struct Fact {
76	    pub name: String,
77	    pub args: Vec<Term>,
78	}
79	
80	impl Fact {
81	    pub fn new(name: &str, args: Vec<Term>) -> Self {
82	        Fact { name: name.to_string(), args }
83	    }
84	
85	    /// Flat (un-wrapped, un-escaped) surface rendering with **fact spacing**:
86	    /// `Name( a, b )`, and `Name( )` when it has no arguments. Argument terms use
87	    /// the ordinary term rendering (functions `f(a, b)` without inner spaces,
88	    /// tuples `<a, b>`). This matches every un-wrapped fact cell in the corpus.
89	    pub fn render_flat(&self) -> String {
90	        let inner: Vec<String> = self.args.iter().map(Term::render_full).collect();
91	        pad(&self.name, &inner)
92	    }
93	
94	    /// Flat rendering with abbreviations applied to registered sub-terms
95	    /// (`table` maps a term's full rendering to its abbreviation name).
96	    pub fn render_flat_abbrev(&self, table: &std::collections::HashMap<String, String>) -> String {
97	        let inner: Vec<String> = self.args.iter().map(|t| t.render_abbrev(table)).collect();
98	        pad(&self.name, &inner)
99	    }
100	}
101	
102	/// Fact spacing `Name( a, b )`, collapsing to `Name( )` for zero arguments
103	/// (observed: `NoA( )`, `!Semistate_1( )` — a single space between the parens).
104	fn pad(name: &str, args: &[String]) -> String {
105	    if args.is_empty() {
106	        format!("{}( )", name)
107	    } else {
108	        format!("{}( {} )", name, args.join(", "))
109	    }
110	}
111	
112	/// The info cell of a rule instance: `#<temporal> : <rule>` plus, when the rule
113	/// has action facts, `[<action>, …]`. Matches the observed info-cell shape
114	/// (`#i : I_Complete[Complete( … ), …]`, or a bare `#vf.5 : Fresh`).
115	pub fn render_info(temporal: &str, rule: &str, actions: &[Fact]) -> String {
116	    if actions.is_empty() {
117	        format!("#{} : {}", temporal, rule)
118	    } else {
119	        let acts: Vec<String> = actions.iter().map(Fact::render_flat).collect();
120	        format!("#{} : {}[{}]", temporal, rule, acts.join(", "))
121	    }
122	}
123	
124	/// Lay `items` out as a **fill** to a target `width`, starting at column
125	/// `open_col` (the alignment column of the group's first element). Returns the
126	/// physical lines *without* the `&nbsp;` indent — [`join_wrapped`] adds it.
127	///
128	/// Greedy fill: keep appending `sep`-joined items to the current line while it
129	/// fits in `width`; otherwise start a new line. This reproduces the observed
130	/// packing (several short arguments share a line, then a break) **given** the
131	/// width; the width itself is the documented gap.
132	pub fn fill(items: &[String], sep: &str, open_col: usize, width: usize) -> Vec<String> {
133	    if items.is_empty() {
134	        return vec![String::new()];
135	    }
136	    let mut lines: Vec<String> = Vec::new();
137	    let mut cur = String::new();
138	    let mut col = open_col;
139	    for (i, it) in items.iter().enumerate() {
140	        let piece = if cur.is_empty() {
141	            it.clone()
142	        } else {
143	            format!("{}{}", sep, it)
144	        };
145	        if !cur.is_empty() && col + piece.chars().count() > width {
146	            lines.push(std::mem::take(&mut cur));
147	            col = open_col;
148	            cur.push_str(it);
149	            col += it.chars().count();
150	        } else {
151	            cur.push_str(&piece);
152	            col += piece.chars().count();
153	        }
154	        let _ = i;
155	    }
156	    lines.push(cur);
157	    lines
158	}
