160	/// Greedy paragraph fill at the **known** width [`FILL_WIDTH`], reproducing the
161	/// observed record-cell packing: elements are laid left-to-right starting at
162	/// column `open_col`; the separator `sep` (e.g. `", "`) is emitted after each
163	/// element and **stays on the current line**, and the next element starts a new
164	/// line iff it would push past [`FILL_WIDTH`] from that point. This reproduces the
165	/// observed first-line packing exactly (e.g. an `Out( <'a01', … > )` whose tuple
166	/// overflows keeps eleven `'aNN'` elements plus the trailing `", "` on line 0,
167	/// then breaks). Continuation lines carry the [`FILL_WIDTH`]-wide `&nbsp;` indent
168	/// via [`join_wrapped`].
169	///
170	/// KNOWN RESIDUAL (BEHAVIOR.md §3f): tamarin's underlying `fsep`-style combinator
171	/// has a one-element lookahead that lets a *continuation* line hold one more
172	/// element than the first line at the same start column; this greedy pass packs
173	/// the first line exactly but a continuation line one element short of that
174	/// lookahead, and it does not model the closing-delimiter peel (`>`/`)` onto their
175	/// own aligned lines) that appears when the last element fills the line.
176	pub fn paragraph_fill(items: &[String], sep: &str, open_col: usize) -> Vec<String> {
177	    if items.is_empty() {
178	        return vec![String::new()];
179	    }
180	    let sep_w = sep.chars().count();
181	    let mut lines: Vec<String> = Vec::new();
182	    let mut cur = String::new();
183	    let mut col = open_col;
184	    for (i, it) in items.iter().enumerate() {
185	        let w = it.chars().count();
186	        if i == 0 {
187	            cur.push_str(it);
188	            col += w;
189	        } else if col + w <= FILL_WIDTH {
190	            cur.push_str(it);
191	            col += w;
192	        } else {
193	            lines.push(std::mem::take(&mut cur));
194	            col = open_col;
195	            cur.push_str(it);
196	            col += w;
197	        }
198	        if i + 1 < items.len() {
199	            // The separator trails the element it follows and stays on the line;
200	            // the *next* element's fit is tested from past it.
201	            cur.push_str(sep);
202	            col += sep_w;
203	        }
204	    }
205	    lines.push(cur);
206	    lines
207	}
208	
209	/// Join physical `lines` (a FILL of same-aligned elements, e.g. a broken action
210	/// list `[a1, a2]`) into a single record-cell string using the observed wrap
211	/// format: each physical line is followed by `\l`, and every continuation line is
212	/// prefixed by `open_col` `&nbsp;` entities (the verified alignment indent). The
213	/// trailing `\l` after the last line is part of the observed format (graphviz
214	/// left-justification). The caller escapes the line contents first (via
215	/// [`escape_record`]) — `\l` and `&nbsp;` are literal control sequences and must
216	/// not be escaped.
217	///
218	/// This reproduces the fill case where the closing delimiter stays attached to
219	/// the last element (`… )]`). A function/fact whose closing `)` breaks onto its
220	/// *own* line at the functor column is a distinct layout the pretty-printer's
221	/// break decision produces (a documented GAP), not modelled here.
222	pub fn join_wrapped(lines: &[String], open_col: usize) -> String {
223	    let indent = "&nbsp;".repeat(open_col);
224	    let mut out = String::new();
225	    for (i, ln) in lines.iter().enumerate() {
226	        if i > 0 {
227	            out.push_str(&indent);
228	        }
229	        out.push_str(ln);
230	        out.push_str("\\l");
231	    }
232	    out
233	}
