1	//! A minimal term model, sufficient to drive abbreviation (naming + expansion
2	//! rendering). It is an independent design; it renders tamarin-like surface
3	//! syntax for the common term shapes observed in legend expansions
4	//! (variables, constants, pairs, `exp`/`mult`/`union`/`xor`, function apps).
5	//!
6	//! Faithful reproduction of the solver's full term pretty-printer (all operators,
7	//! precedence, line wrapping) is out of scope — see BEHAVIOR.md §3a/§5. The
8	//! covered shapes are byte-tested against captured legend rows.
9	
10	use std::collections::HashMap;
11	
12	/// A term. Variable kinds mirror tamarin's surface decorations.
13	#[derive(Clone, Debug, PartialEq, Eq)]
14	pub enum Term {
15	    /// Fresh variable, rendered `~name`.
16	    Fresh(String),
17	    /// Public variable, rendered `$name`.
18	    Pub(String),
19	    /// Bare message/temporal variable, rendered `name`.
20	    Msg(String),
21	    /// Public constant, rendered `'name'`.
22	    Const(String),
23	    /// Right-nested pair; rendered flattened as `<a, b, c>`.
24	    Pair(Box<Term>, Box<Term>),
25	    /// `exp(base, e)`, rendered `base^e` (the exponent carries its own parens
26	    /// when it is a product/sum).
27	    Exp(Box<Term>, Box<Term>),
28	    /// An associative-commutative operator rendered infix inside parentheses:
29	    /// `mult`→`*`, `union`→`++`, `xor`→`⊕`. `func` is the logical name used for
30	    /// the abbreviation prefix.
31	    Ac { func: String, op: String, args: Vec<Term> },
32	    /// Ordinary prefix application `func(a, b, …)`.
33	    App { func: String, args: Vec<Term> },
34	}
35	
36	impl Term {
37	    // ---- convenience constructors --------------------------------------
38	
39	    pub fn fresh(n: &str) -> Term {
40	        Term::Fresh(n.to_string())
41	    }
42	    pub fn pubv(n: &str) -> Term {
43	        Term::Pub(n.to_string())
44	    }
45	    pub fn msg(n: &str) -> Term {
46	        Term::Msg(n.to_string())
47	    }
48	    pub fn cst(n: &str) -> Term {
49	        Term::Const(n.to_string())
50	    }
51	    pub fn app(func: &str, args: Vec<Term>) -> Term {
52	        Term::App { func: func.to_string(), args }
53	    }
54	    pub fn exp(base: Term, e: Term) -> Term {
55	        Term::Exp(Box::new(base), Box::new(e))
56	    }
57	    pub fn mult(args: Vec<Term>) -> Term {
58	        Term::Ac { func: "mult".into(), op: "*".into(), args }
59	    }
60	    pub fn union(args: Vec<Term>) -> Term {
61	        Term::Ac { func: "union".into(), op: "++".into(), args }
62	    }
63	    pub fn xor(args: Vec<Term>) -> Term {
64	        Term::Ac { func: "xor".into(), op: "\u{2295}".into(), args }
65	    }
66	    /// Build a flattened tuple `<a, b, c>` from ≥1 elements (right-nested pairs).
67	    pub fn tuple(mut elems: Vec<Term>) -> Term {
68	        let last = elems.pop().expect("tuple needs ≥1 element");
69	        elems.into_iter().rev().fold(last, |acc, e| Term::Pair(Box::new(e), Box::new(acc)))
70	    }
71	
72	    // ---- naming --------------------------------------------------------
73	
74	    /// The root symbol's *name*, whose first two letters give the abbreviation
75	    /// prefix (see [`crate::abbrev::prefix_for_symbol`]).
76	    pub fn root_symbol_name(&self) -> String {
77	        match self {
78	            Term::Fresh(n) | Term::Pub(n) | Term::Msg(n) | Term::Const(n) => n.clone(),
79	            Term::Pair(..) => "pair".to_string(),
80	            Term::Exp(..) => "exp".to_string(),
81	            Term::Ac { func, .. } => func.clone(),
82	            Term::App { func, .. } => func.clone(),
83	        }
84	    }
85	
86	    /// Leaf terms (variables/constants) are atomic; everything else is not.
87	    pub fn is_atomic(&self) -> bool {
88	        matches!(self, Term::Fresh(_) | Term::Pub(_) | Term::Msg(_) | Term::Const(_))
89	    }
90	
91	    /// A tuple / pair `<a, b, …>`. Tuples are never abbreviated (BEHAVIOR.md §5c,
92	    /// observed: 0 of 97 538 legend entries is a top-level tuple, and a live probe
93	    /// left a length-18 tuple occurring twice un-abbreviated).
94	    pub fn is_tuple(&self) -> bool {
95	        matches!(self, Term::Pair(..))
96	    }
97	
98	    /// Number of Unicode scalar values in the fully-expanded surface rendering —
99	    /// the measure that gates abbreviation (BEHAVIOR.md §5c). This counts the
100	    /// surface decorations too (`'…'` quotes, `~`/`$` sigils), matching the
101	    /// observed boundary (`'12345678'` = 10 chars is abbreviated, `'1234567'` = 9
102	    /// is not).
103	    pub fn render_len(&self) -> usize {
104	        self.render_full().chars().count()
105	    }
106	
107	    /// Number of term nodes (atoms + operators) — a simple complexity measure.
108	    pub fn size(&self) -> usize {
109	        match self {
110	            Term::Fresh(_) | Term::Pub(_) | Term::Msg(_) | Term::Const(_) => 1,
111	            Term::Pair(a, b) => 1 + a.size() + b.size(),
112	            Term::Exp(a, b) => 1 + a.size() + b.size(),
113	            Term::Ac { args, .. } | Term::App { args, .. } => {
114	                1 + args.iter().map(Term::size).sum::<usize>()
115	            }
116	        }
117	    }
118	
119	    /// Visit this term and every sub-term (pre-order).
120	    pub fn for_each_subterm(&self, f: &mut dyn FnMut(&Term)) {
121	        f(self);
122	        match self {
123	            Term::Pair(a, b) | Term::Exp(a, b) => {
124	                a.for_each_subterm(f);
125	                b.for_each_subterm(f);
126	            }
127	            Term::Ac { args, .. } | Term::App { args, .. } => {
128	                for a in args {
129	                    a.for_each_subterm(f);
130	                }
131	            }
132	            _ => {}
133	        }
134	    }
135	
136	    // ---- rendering -----------------------------------------------------
137	
138	    /// Fully-expanded surface rendering (no abbreviations). Used as the dedup key.
139	    pub fn render_full(&self) -> String {
140	        self.render_with(&|t| t.render_full())
141	    }
142	
143	    /// Render this term's expansion, replacing any *registered* sub-term (present
144	    /// in `table`, keyed by its full rendering) with its abbreviation name. The
145	    /// top-level term itself is always rendered structurally.
146	    pub fn render_abbrev(&self, table: &HashMap<String, String>) -> String {
147	        self.render_with(&|t| t.substitute(table))
148	    }
149	
150	    /// Rendering used for children during abbreviation: a registered term yields
151	    /// its name, otherwise it renders structurally (recursing on its children).
152	    fn substitute(&self, table: &HashMap<String, String>) -> String {
153	        if let Some(name) = table.get(&self.render_full()) {
154	            return name.clone();
155	        }
156	        self.render_with(&|t| t.substitute(table))
157	    }
158	
159	    /// Structural rendering; `child` renders each immediate sub-term.
160	    fn render_with(&self, child: &dyn Fn(&Term) -> String) -> String {
161	        match self {
162	            Term::Fresh(n) => format!("~{}", n),
163	            Term::Pub(n) => format!("${}", n),
164	            Term::Msg(n) => n.clone(),
165	            Term::Const(n) => format!("'{}'", n),
166	            Term::Pair(..) => {
167	                let elems = self.pair_spine();
168	                let parts: Vec<String> = elems.iter().map(|t| child(t)).collect();
169	                format!("<{}>", parts.join(", "))
170	            }
171	            Term::Exp(base, e) => format!("{}^{}", child(base), child(e)),
172	            Term::Ac { op, args, .. } => {
173	                let parts: Vec<String> = args.iter().map(|t| child(t)).collect();
174	                format!("({})", parts.join(op))
175	            }
176	            Term::App { func, args } => {
177	                let parts: Vec<String> = args.iter().map(|t| child(t)).collect();
178	                format!("{}({})", func, parts.join(", "))
179	            }
180	        }
181	    }
182	
183	    /// Flatten a right-nested pair into its element spine.
184	    fn pair_spine(&self) -> Vec<&Term> {
185	        let mut out = Vec::new();
186	        let mut cur = self;
187	        while let Term::Pair(a, b) = cur {
188	            out.push(a.as_ref());
189	            cur = b.as_ref();
190	        }
191	        out.push(cur);
192	        out
193	    }
194	}
