167	/// The interactive server's per-theory state: the version map plus the monotonic
168	/// next-index counter. Generic over the prover callbacks.
169	pub struct Server<T: ProverOps> {
170	    ops: T,
171	    /// index -> theory version. Version 1 is the originally loaded theory.
172	    versions: BTreeMap<u64, T::Theory>,
173	    /// Next free version index (monotonic; `= max ever allocated + 1`).
174	    next_index: u64,
175	}
176	
177	impl<T: ProverOps> Server<T> {
178	    /// Create a server holding `base` as version 1.
179	    pub fn new(ops: T, base: T::Theory) -> Server<T> {
180	        let mut versions = BTreeMap::new();
181	        versions.insert(1, base);
182	        Server { ops, versions, next_index: 2 }
183	    }
184	
185	    /// Version indices currently allocated (ascending). All are resolvable.
186	    pub fn versions(&self) -> Vec<u64> {
187	        self.versions.keys().copied().collect()
188	    }
189	
190	    fn resolve(&self, index: &Index) -> Option<u64> {
191	        // Real requests always carry a numeric index; `#` is a crawl placeholder
192	        // that never reaches a live server (a literal `#` is a URL fragment, and
193	        // `%23` 404s — live [L2]), so it resolves to nothing here.
194	        match index {
195	            Index::Num(v) if self.versions.contains_key(v) => Some(*v),
196	            _ => None,
197	        }
198	    }
199	
200	    /// Dispatch a request to a response, mutating version state as observed.
201	    pub fn dispatch(&mut self, req: &Request) -> Response {
202	        let route = match Route::parse(req.path) {
203	            Some(r) => r,
204	            None => return Response::not_found(req.path),
205	        };
206	        let index = match self.resolve(&route.index) {
207	            Some(v) => v,
208	            None => return Response::not_found(req.path),
209	        };
210	        match (req.method, &route.handler) {
211	            // `main/method` is delivered under `main` but is a proof operation
212	            // (allocates a new version); intercept it before the read-only views.
213	            (HttpMethod::Get, Handler::Main(Main::Method { lemma, n, path })) => {
214	                self.get_method(index, &lemma.clone(), *n, &path.clone())
215	            }
216	            (HttpMethod::Get, Handler::Main(m)) => self.get_main(index, m),
217	            (HttpMethod::Get, Handler::Overview(tail)) => self.get_overview(index, &OverviewView::parse(tail)),
218	            (HttpMethod::Get, Handler::Autoprove(tail)) => match Autoprove::parse(tail) {
219	                Some(ap) => self.proof_op_autoprove(index, &ap),
220	                None => Response::not_found(req.path),
221	            },
222	            (HttpMethod::Get, Handler::Next(tail)) => self.get_nav(index, NavDir::Next, tail, req.path),
223	            (HttpMethod::Get, Handler::Prev(tail)) => self.get_nav(index, NavDir::Prev, tail, req.path),
224	            (HttpMethod::Get, Handler::Source) | (HttpMethod::Get, Handler::Message) => {
225	                Response::text(self.ops.source_text(&self.versions[&index]))
226	            }
227	            (HttpMethod::Get, Handler::Intdot(tail)) => self.get_intdot(index, tail),
228	            (HttpMethod::Get, Handler::InteractiveGraphDef(tail)) => {
229	                Response::text(self.ops.graph_dot(&self.versions[&index], tail))
230	            }
231	            // Structural-edit POST form targets: /thy/trace/V/edit/{verb}/{name}
232	            (HttpMethod::Post, Handler::Other { name, tail }) if name == "edit" => {
233	                self.post_edit(index, tail, req)
234	            }
235	            _ => Response::not_found(req.path),
236	        }
237	    }
238	
239	    // ---- GET main/* : JSON envelopes ----
240	    fn get_main(&self, index: u64, m: &Main) -> Response {
241	        let thy = &self.versions[&index];
242	        let content = match m {
243	            Main::Help => self.ops.main_content(thy, index, &MainReq::Help),
244	            Main::Message => self.ops.main_content(thy, index, &MainReq::Message),
245	            Main::Rules => self.ops.main_content(thy, index, &MainReq::Rules),
246	            Main::Tactic => self.ops.main_content(thy, index, &MainReq::Tactic),
247	            Main::Cases { refined, level, n } => {
248	                self.ops.main_content(thy, index, &MainReq::Cases { refined: *refined, level: *level, n: *n })
249	            }
250	            Main::Lemma(name) => self.ops.main_content(thy, index, &MainReq::Lemma(name)),
251	            Main::Proof { lemma, path } => {
252	                self.ops.main_content(thy, index, &MainReq::Proof { lemma, path })
253	            }
254	            // Forms are web-layer templates; only the edit form needs prover input.
255	            Main::Edit(name) => {
256	                let src = self.ops.lemma_source(thy, name).unwrap_or_default();
257	                Content { html: forms::edit_form(name, &src), title: format!("Edit Lemma: {name}") }
258	            }
259	            Main::Add(pos) => Content { html: forms::add_form(pos), title: "Add new Lemma".to_string() },
260	            Main::Delete(name) => Content { html: forms::delete_form(name), title: format!("Delete {name}") },
261	            // `Method` is a proof op intercepted in `dispatch`; unreachable here.
262	            Main::Method { .. } => return Response::not_found("method"),
263	            Main::Other(_) => return Response::not_found("main"),
264	        };
265	        Response::json(envelope::render_content(&content.html, &content.title))
266	    }
