317	    // ---- proof operations: allocate a NEW version, answer JSON {redirect} ----
318	    fn get_method(&mut self, index: u64, lemma: &str, n: usize, path: &[String]) -> Response {
319	        let (new_thy, focus) = self.ops.apply_method(&self.versions[&index], lemma, n, path);
320	        let new_index = self.commit_new_version(new_thy);
321	        Response::json(envelope::render_redirect(&overview_proof_path(new_index, lemma, &focus)))
322	    }
