337	    // ---- structural POST: mutate IN PLACE, answer 303 (or 200 form on failure) ----
338	    fn post_edit(&mut self, index: u64, tail: &[String], req: &Request) -> Response {
339	        let (verb, name) = match tail {
340	            [v, n] => match EditVerb::parse(v) {
341	                Some(verb) => (verb, n.clone()),
342	                None => return Response::not_found(req.path),
343	            },
344	            _ => return Response::not_found(req.path),
345	        };
346	        match verb {
347	            EditVerb::Delete => {
348	                let new_thy = self.ops.delete_lemma(&self.versions[&index], &name);
349	                self.versions.insert(index, new_thy);
350	                Response::see_other(format!("/thy/trace/{index}/overview/help"))
351	            }
352	            EditVerb::Edit => {
353	                let text = req.field("lemma-text");
354	                match self.ops.edit_lemma(&self.versions[&index], &name, text) {
355	                    Some(new_thy) => {
356	                        self.versions.insert(index, new_thy);
357	                        Response::see_other(format!("/thy/trace/{index}/overview/edit/{name}"))
358	                    }
359	                    // Failure: theory unchanged, re-render the full-page edit form.
360	                    None => self.get_overview(index, &OverviewView::Edit(name)),
361	                }
362	            }
363	            EditVerb::Add => {
364	                let text = req.field("lemma-text");
365	                match self.ops.add_lemma(&self.versions[&index], &name, text) {
366	                    Some(new_thy) => {
367	                        self.versions.insert(index, new_thy);
368	                        Response::see_other(format!("/thy/trace/{index}/overview/add/{name}"))
369	                    }
370	                    None => self.get_overview(index, &OverviewView::Add(name)),
371	                }
372	            }
373	        }
374	    }
