376	    /// Apply a proof method that arrived as a parsed `Main::Method` (proof op).
377	    /// Exposed so a caller that pre-parses `main/method` can drive the version
378	    /// bump directly; the normal path routes GET `main/method` through here.
379	    pub fn apply_main_method(&mut self, index: u64, lemma: &str, n: usize, path: &[String]) -> Response {
380	        self.get_method(index, lemma, n, path)
381	    }
382	}
