384	/// Build an `overview/proof/{lemma}[/focus…]` URL for version `index`.
385	fn overview_proof_path(index: u64, lemma: &str, focus: &[String]) -> String {
386	    let mut s = format!("/thy/trace/{index}/overview/proof/{lemma}");
387	    for seg in focus {
388	        s.push('/');
389	        s.push_str(seg);
390	    }
391	    s
392	}
